#!/usr/bin/env python3\nimport os, sys\nfrom pathlib import Path\nfrom dotenv import load_dotenv\nimport json, re, uuid\nfrom datetime import datetime\n\nENV_PATH = Path('.env')\nENV_EXAMPLE = Path('.env.example')\nif not ENV_PATH.exists():\n    if ENV_EXAMPLE.exists():\n        import shutil\n        shutil.copy(ENV_EXAMPLE, ENV_PATH)\n        print('.env created from .env.example. Please add GEMINI_API_KEY and re-run.')\n        sys.exit(0)\n    else:\n        print('.env.example missing. Create .env manually. Exiting.')\n        sys.exit(1)\nload_dotenv(dotenv_path=ENV_PATH)\nGEMINI_API_KEY = os.getenv('GEMINI_API_KEY','').strip()\nif not GEMINI_API_KEY or 'YOUR_GEMINI_API_KEY' in GEMINI_API_KEY:\n    print('GEMINI_API_KEY not set or placeholder. Please set it in .env. Exiting.')\n    sys.exit(1)\nprint('GEMINI_API_KEY present. Demo generator ready (no external calls in this demo).')\nOUTPUT_DIR = Path('output')\nOUTPUT_DIR.mkdir(exist_ok=True)\ndef now_iso():\n    from datetime import datetime\n    return datetime.utcnow().isoformat()+'Z'\ndef mask_account(a):\n    if not a: return None\n    s=str(a)\n    return 'XXXX'+s[-4:] if len(s)>4 else 'XXXX'+s\ndef mask_phone(p):\n    import re\n    if not p: return None\n    d=re.sub(r'\\D','',p)\n    return d[:4]+'XXXX'+d[-3:] if len(d)>7 else 'XXXX'+d\ndef gen_case_id():\n    import uuid\n    return 'UBD-'+uuid.uuid4().hex[:8].upper()\nrec = { 'id': 9001, 'language':'Pidgin', 'scenario':'UnauthorizedDebit', 'meta':{'case_id': gen_case_id(), 'timestamp': now_iso()} }\nwith open(OUTPUT_DIR/'AllTranscripts.json','w') as f:\n    json.dump([rec], f, indent=2)\nprint('Demo output written to output/AllTranscripts.json')\n